#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=5e6+5;
int ksm(int a,int b,int p) {
	int ans=1;
	while(b) {
		if(b&1) {
			ans=(ans*a)%p;
		}
		a=(a*a)%p;
		b>>=1;
	}
	return ans;
}
int c1[maxn],c2[maxn],x;
void sx(int p) {
	c1[0]=c2[0]=1;
	for(int i=1; i<=p; i++) {
		c1[i]=c1[i-1]*i%p;
		c2[i]=c2[i-1]*ksm(i,p-2,p)%p;;
	}
}
int C(int n,int m,int p) {
	if(m<0||m>n) {
		return 0;
	}
	return c1[n]*c2[m]%p*c2[n-m]%p;
}
int lks(int n,int m,int p) {
	if(m==0) {
		return 1;
	}
	return C(n%p,m%p,p)*lks(n/p,m/p,p)%p;
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int t,n,m,ans=0,p;
	cin>>t;
	while(t--) {
		cin>>n>>m>>p;
		sx(p);
		cout<<lks(n+m,n,p)<<"\n";
	}
	return 0;
}
